function silverPermission(mysqli $conn,string $action):bool{
    if(($_SESSION['user_type']??'')==='Platform Admin') return true;
    $map=['open'=>'can_open','view'=>'can_view','value'=>'can_view_value','create'=>'can_create','update'=>'can_update','delete'=>'can_delete'];
    $field=$map[$action]??''; if($field==='') return false;
    $codes=['perm.inventory.silver_rates','perm.rates.silver','perm.silver_rates','perm.inventory.metal_rates','perm.inventory'];
    $permissions=$_SESSION['permissions']??[];
    foreach($codes as $code){if(isset($permissions[$code])&&array_key_exists($field,$permissions[$code])) return (int)$permissions[$code][$field]===1;}
    $businessId=(int)($_SESSION['business_id']??0);$roleId=(int)($_SESSION['role_id']??0);if($businessId<=0||$roleId<=0)return false;
    $marks=implode(',',array_fill(0,count($codes),'?'));$sql="SELECT rp.`{$field}` FROM role_permissions rp INNER JOIN permissions p ON p.id=rp.permission_id WHERE rp.business_id=? AND rp.role_id=? AND p.is_active=1 AND p.permission_code IN ($marks) ORDER BY FIELD(p.permission_code,".implode(',',array_fill(0,count($codes),'?')).") LIMIT 1";
    $stmt=$conn->prepare($sql);if(!$stmt)return false;$types='ii'.str_repeat('s',count($codes)*2);$values=array_merge([$businessId,$roleId],$codes,$codes);$stmt->bind_param($types,...$values);$stmt->execute();$row=$stmt->get_result()->fetch_assoc();$stmt->close();return (int)($row[$field]??0)===1;
}
