$canView=silverPermission($conn,'view')||silverPermission($conn,'open');$canValue=silverPermission($conn,'value')||$canView;$canCreate=silverPermission($conn,'create');$canUpdate=silverPermission($conn,'update');$canDelete=silverPermission($conn,'delete');
$businessId=(int)($_SESSION['business_id']??0);if($businessId<=0)die('A valid business must be selected.');
