$conn->query("CREATE TABLE IF NOT EXISTS silver_rate_history (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,business_id BIGINT UNSIGNED NOT NULL,rate_date DATE NOT NULL,purity VARCHAR(20) NOT NULL DEFAULT '925',rate_per_gram DECIMAL(14,2) NOT NULL DEFAULT 0.00,rate_per_kg DECIMAL(16,2) GENERATED ALWAYS AS (rate_per_gram*1000) STORED,remarks VARCHAR(255) DEFAULT NULL,updated_by BIGINT UNSIGNED DEFAULT NULL,created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_silver_rate (business_id,rate_date,purity),KEY idx_silver_date (business_id,rate_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
$purities=[];$stmt=$conn->prepare('SELECT DISTINCT purity FROM silver_rate_history WHERE business_id=? ORDER BY CAST(purity AS UNSIGNED) DESC');if($stmt){$stmt->bind_param('i',$businessId);$stmt->execute();$r=$stmt->get_result();while($x=$r->fetch_assoc())$purities[]=$x['purity'];$stmt->close();}
$theme=['primary_color'=>'#d89416','primary_dark_color'=>'#b86a0b','primary_soft_color'=>'#fff6e5','sidebar_gradient_1'=>'#171c21','sidebar_gradient_2'=>'#20272d','sidebar_gradient_3'=>'#101419','page_background'=>'#f4f3f0','card_background'=>'#fff','text_color'=>'#171717','muted_text_color'=>'#7d8794','border_color'=>'#e8e8e8','font_family'=>'Inter','heading_font_family'=>'Playfair Display','border_radius_px'=>12,'sidebar_width_px'=>230];
