ast{position:fixed;right:18px;top:78px;z-index:20000;padding:11px 14px;border-radius:10px;color:#fff;font-size:11px;font-weight:600;opacity:0;transform:translateY(-10px);transition:.2s}.theme-toast.show{opacity:1;transform:none}.theme-toast-success{background:#168449}.theme-toast-error{background:#c0392b}.modal-content{background:var(--card-bg);color:var(--text);border:0;border-radius:var(--radius)}.modal-header,.modal-footer{border-color:var(--line)}.field-label{font-size:10px;font-weight:700;margin-bottom:5px}body.dark-mode,body[data-theme=dark]{--page-bg:#0f151b;--card-bg:#182129;--text:#f3f6f8;--muted:#9aa7b3;--line:#2c3944}@media(max-width:991.98px){.stat-grid{grid-template-columns:repeat(2,1fr)}.filter-grid{grid-template-columns:1fr 1fr}.filter-grid .search-field{grid-column:1/-1}.rate-card{border:0;background:transparent}.rate-table thead{display:none}.rate-table,.rate-table tbody{display:block}.rate-table tbody{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}.rate-table tr{display:grid;grid-template-columns:1fr 1fr;padding:14px;border:1px solid var(--line);border-radius:var(--radius);background:var(--card-bg)}.rate-table td{display:flex;justify-content:space-between;padding:8px 0;border:0;border-bottom:1px dashed var(--line);text-align:right!important}.rate-table td:before{content:attr(data-label);font-size:9px;font-weight:700;color:var(--muted);text-transform:uppercase}.rate-table td.actions{grid-column:1/-1;border:0}.pagination-wrap{border:1px solid var(--line);border-radius:var(--radius);margin-top:10px;background:var(--card-bg)}}@media(max-width:767.98px){.filter-grid{grid-template-columns:1fr}.filter-grid .search-field{grid-column:auto}.rate-table tbody{grid-template-columns:1fr}.rate-table tr{grid-template-columns:1fr}.rate-table td{grid-column:1/-1}.pagination-wrap{flex-direction:column;align-items:flex-start;gap:8px}}
