oreach?></select></div><button type="button" class="btn-reset" id="reset"><i class="fa-solid fa-rotate-left"></i>Reset</button><?php if($canCreate||$canUpdate):?><button type="button" class="btn-theme" id="addRate"><i class="fa-solid fa-plus"></i>Add Rate</button><?php endif?></form></div><section class="rate-card" id="listSection"><div class="loading" id="loading"><div><i class="fa-solid fa-spinner fa-spin me-2"></i>Loading...</div></div><div class="table-responsive"><table class="table rate-table"><thead><tr><th>Date</th><th>Purity</th><?php if($canValue):?><th>Rate / Gram</th><th>Rate / Kg</th><?php endif?><th>Remarks</th><th>Updated By</th><th class="text-end">Actions</th></tr></thead><tbody id="tableBody"></tbody></table></div><div class="empty-state d-none" id="empty"><i class="fa-regular fa-folder-open fa-2x mb-2"></i><div>No silver rates found.</div></div><div class="pagination-wrap"><div class="pagination-summary" id="summary">Showing 0 rates</div><ul class="pagination pagination-sm" id="pagination"></ul></div></section><?php endif?><?php include('includes/footer.php'); ?></div></main>
