<?php include('includes/script.php'); ?><script src="assets/js/script.js"></script><?php if($canView):?><script>
(()=>{'use strict';const csrf=<?=json_encode($csrfToken)?>,canUpdate=<?=$canUpdate?'true':'false'?>,canDelete=<?=$canDelete?'true':'false'?>,currency=<?=json_encode((string)($_SESSION['currency_symbol']??'₹'))?>;const el=id=>document.getElementById(id),search=el('search'),purity=el('purity'),month=el('month'),perPage=el('perPage'),body=el('tableBody'),empty=el('empty'),loading=el('loading'),pagination=el('pagination'),summary=el('summary');let page=<?=$initialPage?>,timer,controller;const modal=new bootstrap.Modal(el('rateModal'));function esc(v){return String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}function toast(t,m){const x=document.createElement('div');x.className='theme-toast theme-toast-'+t;x.textContent=m;document.body.appendChild(x);requestAnimationFrame(()=>x.classList.add('show'));setTimeout(()=>{x.classList.remove('show');setTimeout(()=>x.remove(),250)},3000)}function state(p=page){return{search:search.value.trim(),purity:purity.value,month:month.value,per_page:perPage.value,page:p}}function url(s,replace=false){const u=new URL(location.href);['search','purity','month','per_page','page'].forEach(k=>u.searchParams.delete(k));Object.entries(s).forEach(([k,v])=>{if(v&&!(k==='per_page'&&v==='10')&&!(k==='page'&&Number(v)===1))u.searchParams.set(k,v)});history[replace?'replaceState':'pushState'](s,'',u)}function row(r){let a='';if(canUpdate)a+='<button class="action-btn edit" data-id="'+r.id+'" title="Edit"><i class="fa-solid fa-pen"></i></button>';if(canDelete)a+='<button class="action-btn danger delete" data-id="'+r.id+'" data-name="'+esc(r.purity)+'" title="Delete"><i class="fa-solid fa-trash"></i></button>';return'<tr><td data-label="Date">'+esc(r.rate_date_display)+'</td><td data-label="Purity"><span class="badge-soft">'+esc(r.purity)+'</span></td>'+<?= $canValue ? "'<td data-label=\"Rate / Gram\"><span class=\"rate-value\">'+esc(currency)+Number(r.rate_per_gram).toFixed(2)+'</span></td><td data-label=\"Rate / Kg\">'+esc(currency)+Number(r.rate_per_kg).toLocaleString(undefined,{minimumFractionDigits:2})+'</td>'" : "''" ?>+'<td data-label="Remarks">'+esc(r.remarks||'—')+'</td><td data-label="Updated By">'+esc(r.updated_by_name||'—')+'</td><td data-label="Actions" class="actions text-end"><div class="d-inline-flex gap-1">'+a+'</div></td></tr>'}function pageBtn(label,p,disabled=false,active=false){return'<li class="page-item '+(disabled?'disabled ':'')+(active?'active':'')+'"><button type="button" class="page-link" data-page="'+p+'">'+label+'</button></li>'}function renderPager(m){pagination.innerHTML='';let out=pageBtn('<i class="fa-solid fa-angle-left"></i>',m.page-1,m.page<=1);for(let i=Math.max(1,m.page-2);i<=Math.min(m.total_pages,m.page+2);i++)out+=pageBtn(i,i,false,i===m.page);out+=pageBtn('<i class="fa-solid fa-angle-right"></i>',m.page+1,m.page>=m.total_pages);pagination.innerHTML=out;summary.textContent=m.total?'Showing '+m.from+'–'+m.to+' of '+m.total+' rates':'Showing 0 rates'}async function api(fd){const r=await fetch('api/silver-rates-save.php',{method:'POST',body:fd,credentials:'same-origin',headers:{'X-Requested-With':'XMLHttpRequest'}}),j=await r.json().catch(()=>({success:false,message:'Invalid server response.'}));if(!r.ok||!j.success)throw new Error(j.message||'Request failed.');return j}async function load(opt={}){page=opt.page||page;if(controller)controller.abort();controller=new AbortController();loading.classList.add('show');const fd=new FormData();fd.append('action','list');fd.append('csrf_token',csrf);Object.entries(state()).forEach(([k,v])=>fd.append(k,v));try{const r=await fetch('api/silver-rates-save.php',{method:'POST',body:fd,credentials:'same-origin',headers:{'X-Requested-With':'XMLHttpRequest'},signal:controller.signal}),j=await r.json();if(!r.ok||!j.success)throw new Error(j.message);page=j.meta.page;body.innerHTML=j.rates.map(row).join('');empty.classList.toggle('d-none',j.rates.length>0);body.closest('table').classList.toggle('d-none',j.rates.length===0);renderPager(j.meta);el('statToday').textContent=j.stats.today;el('statPurities').textContent=j.stats.purities;el('statHighest').textContent=currency+Number(j.stats.highest).toFixed(2);el('statTotal').textContent=j.stats.total;url(state(),opt.replace===true);if(opt.scroll)el('listSection').scrollIntoView({behavior:'smooth',block:'start'})}catch(e){if(e.name!=='AbortError')toast('error',e.message)}finally{loading.classList.remove('show')}}function resetForm(){el('rateForm').reset();el('rateId').value='0';el('rateDate').value=new Date().toISOString().slice(0,10);el('ratePurity').value='925';el('modalTitle').textContent='Add Silver Rate';el('ratePerKg').value=''}el('addRate')?.addEventListener('click',()=>{resetForm();modal.show()});el('ratePerGram').addEventListener('input',()=>el('ratePerKg').value=((parseFloat(el('ratePerGram').value)||0)*1000).toFixed(2));search.addEventListener('input',()=>{clearTimeout(timer);timer=setTimeout(()=>{page=1;load({page:1})},350)});[purity,month,perPage].forEach(x=>x.addEventListener('change',()=>{page=1;load({page:1})}));el('reset').addEventListener('click',()=>{search.value='';purity.value='';month.value='';perPage.value='10';page=1;load({page:1})});pagination.addEventListener('click',e=>{const b=e.target.closest('[data-page]');if(!b||b.closest('.disabled')||b.closest('.active'))return;page=Number(b.dataset.page);load({page,scroll:true})});document.addEventListener('click',async e=>{const ed=e.target.closest('.edit');if(ed){const fd=new FormData();fd.append('action','get');fd.append('csrf_token',csrf);fd.append('rate_id',ed.dataset.id);try{const j=await api(fd),r=j.rate;resetForm();el('rateId').value=r.id;el('rateDate').value=r.rate_date;el('ratePurity').value=r.purity;el('ratePerGram').value=r.rate_per_gram;el('remarks').value=r.remarks||'';el('ratePerKg').value=(Number(r.rate_per_gram)*1000).toFixed(2);el('modalTitle').textContent='Edit Silver Rate';modal.show()}catch(x){toast('error',x.message)}}const del=e.target.closest('.delete');if(del){if(!confirm('Delete silver rate for purity '+del.dataset.name+'?'))return;const fd=new FormData();fd.append('action','delete');fd.append('csrf_token',csrf);fd.append('rate_id',del.dataset.id);try{const j=await api(fd);toast('success',j.message);load({page})}catch(x){toast('error',x.message)}}});el('rateForm').addEventListener('submit',async e=>{e.preventDefault();const b=el('saveBtn'),old=b.innerHTML;b.disabled=true;b.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i>Saving...';try{const j=await api(new FormData(e.currentTarget));toast('success',j.message);modal.hide();load({page:1})}catch(x){toast('error',x.message)}finally{b.disabled=false;b.innerHTML=old}});load({replace:true})})();
</script><?php endif?></body></html>
